module top_module(
    input a,
    input b,
    input c,
    output y
);reg not_yi;

    always @(*) begin
        if (a | (b & c)) begin
            not_yi <= 1;
        end else if (a == 0 && b == 0 && c == 0) begin
            not_yi <= 0;
        end
    end

    assign y = not_yi;

endmodule
